#!/usr/bin/env python3
"""Telegram Export Converter — convert between HTML and JSON exports.

Both directions in one module, with auto-detection of what the folder
contains:

  HTML -> JSON   Parses a Telegram HTML chat export (raw, fused,
                 compacted and/or enhanced — enhanced markup is
                 normalized back first) and writes a result.json
                 following Telegram Desktop's own JSON export schema
                 (https://core.telegram.org/import-export). Two modes:
                   * enriched (default): extra keys not present in the
                     official schema (call status texts, file names,
                     generator mark) are injected so no data is lost.
                   * faithful (--faithful): official keys only —
                     DESTRUCTIVE, that extra data is dropped, AND the
                     HTML-only pages/assets (messages*.html, css/, js/,
                     images/) are deleted so the folder ends up
                     matching a genuine JSON export's layout exactly.

  JSON -> HTML   Rebuilds the browsable messages*.html pages from a
                 result.json (official, generated by this tool, or a
                 result_enriched.json if that is all the folder has).
                 The JSON export lacks the static "web" assets of the
                 HTML one (css/, js/, images/), so they are embedded in
                 this module and written alongside the pages.

  Both present   When a folder holds BOTH exports of the same chat,
                 --enrich merges the extra fields recoverable from the
                 HTML into the official result.json (which holds data
                 the HTML lacks: from_id, edited dates, file sizes...)
                 -> result_enriched.json, touching neither original.

  Enriched only  When a folder holds ONLY a result_enriched.json (no
                 HTML, no official result.json), --downgrade strips
                 this tool's extra data back to a plain, official-
                 schema result.json — DESTRUCTIVE, same trade-off as
                 --faithful.

Media files are never copied: they are referenced by the same relative
paths (photos/..., voice_messages/...), which both export layouts share.

Fields that Telegram's HTML export simply does not contain cannot be
recovered when converting HTML -> JSON: numeric ids ("from_id",
"actor_id"), "edited" timestamps, media dimensions, mime types and
file sizes.

Usage:
    python telegram_export_converter.py <export_dir>            # auto
    python telegram_export_converter.py <export_dir> --to-json
                        [--faithful] [-o OUT.json] [--indent N | --compact]
    python telegram_export_converter.py <export_dir> --to-html
                        [--page-size SIZE] [--force]
    python telegram_export_converter.py <export_dir> --enrich [-o OUT.json]
    python telegram_export_converter.py <export_dir> --downgrade [-o OUT.json]

Must live next to telegram_export_fuser.py and
telegram_export_enhancer.py (it reuses their parsers).
"""

import argparse
import base64
import calendar
import html as htmllib
import json
import re
import shutil
import sys
import zlib
from datetime import datetime, timedelta, timezone
from pathlib import Path

from telegram_export_fuser import (
    DEFAULT_PAGE_SIZE, Message, chat_title, merge_messages, parse_export,
    parse_size, report_stage, write_pages,
)
from telegram_export_enhancer import (
    DURATION_RE, STATUS_RE, revert_media, revert_quotes,
)

GENERATOR = "Telegram Export Studio"

# ===========================================================================
# HTML -> JSON
# ===========================================================================

TEXT_DIV_RE = re.compile(r'<div class="text">\s*\n(.*?)\n\s*</div>',
                         re.DOTALL)
SERVICE_BODY_RE = re.compile(
    r'<div class="body details">\s*\n(.*?)\n\s*</div>', re.DOTALL)
TITLE_FULL_RE = re.compile(
    r'<div class="pull_right date details" title="'
    r'(\d{2})\.(\d{2})\.(\d{4}) (\d{2}):(\d{2}):(\d{2})'
    r'(?: UTC([+-]\d{2}):(\d{2}))?"')
REPLY_TO_RE = re.compile(
    r'<div class="reply_to details">.*?#go_to_message(\d+)', re.DOTALL)
PHOTO_RE = re.compile(r'<a class="photo_wrap[^"]*" href="([^"]+)"')
STICKER_RE = re.compile(r'<a class="sticker_wrap[^"]*" href="([^"]+)"')
VIDEO_HREF_RE = re.compile(r'<a class="video_file_wrap[^"]*" href="([^"]+)"')
VIDEO_THUMB_RE = re.compile(r'<img class="video_file" src="([^"]+)"')
MEDIA_LINK_RE = re.compile(
    r'<a class="media clearfix pull_left block_link ([\w-]+)"'
    r' href="([^"]+)"')
MEDIA_CALL_RE = re.compile(r'<div class="media clearfix pull_left media_call')
TITLE_BOLD_RE = re.compile(r'<div class="title bold">\s*\n(.*?)\n', re.DOTALL)
FORWARDED_FROM_RE = re.compile(
    r'<div class="forwarded body">\s*\n\s*<div class="from_name">\s*\n'
    r'\s*(.*?)\s*(?:<span class="date details"|\n)', re.DOTALL)
REACTIONS_OPEN_RE = re.compile(r'<span class="reactions">')
REACTION_EMOJI_RE = re.compile(r'<span class="emoji">\s*(.*?)\s*</span>',
                               re.DOTALL)
REACTION_WHO_RE = re.compile(r'<div class="initials"[^>]*title="([^"]+)"')
REACTION_COUNT_RE = re.compile(r'<span class="count">\s*(\d+)\s*</span>')

# inline formatting inside a text div -> MessageEntity, in document order
ENTITY_RE = re.compile(
    r'<a\s+href\s*=\s*"(?P<href>[^"]*)"[^>]*>(?P<atext>.*?)</a>'
    r'|<(?P<tag>strong|b|em|i|code|pre|u|s|strike|del)>'
    r'(?P<ttext>.*?)</(?P=tag)>'
    r'|<span class="spoiler">(?P<stext>.*?)</span>',
    re.DOTALL)
TAG_ENTITIES = {"strong": "bold", "b": "bold", "em": "italic", "i": "italic",
                "code": "code", "pre": "pre", "u": "underline",
                "s": "strikethrough", "strike": "strikethrough",
                "del": "strikethrough"}

# media_* CSS class of the HTML export -> media_type of Telegram's JSON
# (generic documents carry no media_type in the official schema)
MEDIA_TYPES = {
    "media_voice_message": "voice_message",
    "media_audio_file": "audio_file",
    "media_video": "video_message",
    "media_animation": "animation",
}

# status text of a call in the HTML export -> official discard_reason
CALL_REASONS = (("busy", "busy"), ("declined", "busy"),
                ("disconnect", "disconnect"),
                ("missed", "missed"), ("cancelled", "missed"))

# extra per-message keys of the enriched output that do NOT exist in
# Telegram's official JSON schema; the "faithful" mode strips them
ENRICHED_KEYS = ("status", "file_name")

# top-level folders the HTML export ships that a genuine JSON export never
# has (Telegram Desktop's own JSON export is just result.json + media
# folders) — removed by the faithful mode to match that layout exactly
ASSET_DIRS = ("css", "js", "images")


def _remove_html_assets(d: Path):
    """Delete the HTML-only pages and static assets (messages*.html,
    css/, js/, images/), leaving just result.json + the shared media
    folders — the faithful mode's destructive cleanup."""
    for f in d.glob("messages*.html"):
        f.unlink()
    for sub in ASSET_DIRS:
        shutil.rmtree(d / sub, ignore_errors=True)


def _guard_overwrite(out: Path, mark: str):
    """Refuse to overwrite a JSON file this tool did not generate (e.g.
    Telegram's own official export). Files carrying our top-level mark
    (generated_by / enriched_by) are ours and safe to regenerate."""
    if not out.exists():
        return
    try:
        existing = json.loads(out.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError, UnicodeDecodeError):
        existing = None
    if not (isinstance(existing, dict) and existing.get(mark) == GENERATOR):
        raise ValueError(
            f"Ya existe {out.name} en la carpeta y no lo generó esta "
            "herramienta — sobrescribirlo destruiría el export JSON "
            "original. Usa -o para elegir otro archivo de salida.")


def plain_text(inner_html: str) -> str:
    """Inner HTML -> plain text: <br> to newline, tags out, entities in."""
    text = re.sub(r"<br\s*/?>", "\n", inner_html)
    text = re.sub(r"<[^>]+>", "", text)
    return htmllib.unescape(text)


def text_entities(inner_html: str):
    """Inner HTML of a text div -> list of MessageEntity dicts
    ({"type", "text", ...}), plain runs included as type "plain"."""
    entities = []

    def add_plain(segment):
        text = plain_text(segment)
        if text:
            entities.append({"type": "plain", "text": text})

    pos = 0
    for m in ENTITY_RE.finditer(inner_html):
        add_plain(inner_html[pos:m.start()])
        if m.group("href") is not None:
            href = m.group("href")
            text = plain_text(m.group("atext"))
            if href.lower().endswith((".tgs", ".webp", ".webm")):
                # custom emoji rendered as a link to the sticker file
                entities.append({"type": "custom_emoji", "text": text,
                                 "document_id": href})
            elif text == href:
                entities.append({"type": "link", "text": text})
            else:
                entities.append({"type": "text_link", "text": text,
                                 "href": href})
        elif m.group("tag"):
            entities.append({"type": TAG_ENTITIES[m.group("tag")],
                             "text": plain_text(m.group("ttext"))})
        else:
            entities.append({"type": "spoiler",
                             "text": plain_text(m.group("stext"))})
        pos = m.end()
    add_plain(inner_html[pos:])
    return entities


def entities_to_text(entities):
    """MessageEntity list -> the official "text" value: a plain string
    when there is no formatting, otherwise a mixed array where plain
    entities are unwrapped to bare strings."""
    if not entities:
        return ""
    if len(entities) == 1 and entities[0]["type"] == "plain":
        return entities[0]["text"].strip()
    return [e["text"] if e["type"] == "plain" else e for e in entities]


def _local_offsets(year: int):
    """UTC offsets of the system timezone in winter and summer."""
    return {datetime(year, 1, 15, 12).astimezone().utcoffset(),
            datetime(year, 7, 15, 12).astimezone().utcoffset()}


def parse_date(block: str):
    """Date title of a message -> (iso, unixtime_str_or_None).

    Telegram Desktop stamps every message with the timezone's STANDARD
    offset (e.g. "UTC+01:00" even in summer), while the wall-clock time
    shown is the real, DST-aware local time. If the labelled offset
    belongs to the timezone this machine is in, interpret the date with
    the full local timezone (DST included) so the unixtime matches the
    one in Telegram's own JSON export; otherwise fall back to the
    labelled offset as-is (possibly one hour off during DST).
    """
    m = TITLE_FULL_RE.search(block)
    if not m:
        return None, None
    dd, mo, yy, hh, mi, ss = (int(g) for g in m.groups()[:6])
    date = datetime(yy, mo, dd, hh, mi, ss)
    oh, om = m.group(7), m.group(8)
    if oh is None:
        return date.isoformat(), None
    sign = -1 if oh.startswith("-") else 1
    label = timedelta(hours=int(oh), minutes=sign * int(om))
    if label in _local_offsets(yy):
        stamped = date.astimezone()  # naive -> DST-aware local time
    else:
        stamped = date.replace(tzinfo=timezone(label))
    return date.isoformat(), str(int(stamped.timestamp()))


def duration_from(text: str):
    """'21 seconds' / 'Incoming (64 seconds)' / '0:07' / '(1:02:35)'
    -> seconds; None when the text holds no duration."""
    m = re.search(r"(\d+)\s*seconds?", text)
    if m:
        return int(m.group(1))
    m = (re.search(r"\((\d+(?::\d{1,2}){1,2})\)", text)
         or re.fullmatch(r"(\d+(?::\d{1,2}){1,2})", text.strip()))
    if not m:
        return None
    secs = 0
    for p in m.group(1).split(":"):
        secs = secs * 60 + int(p)
    return secs


def extract_media(block: str):
    """Media references of one message block -> dict of JSON fields."""
    m = PHOTO_RE.search(block)
    if m:
        return {"photo": m.group(1)}

    m = STICKER_RE.search(block)
    if m:
        return {"media_type": "sticker", "file": m.group(1)}

    m = VIDEO_HREF_RE.search(block)
    if m:
        out = {"media_type": "video_file", "file": m.group(1)}
        tm = VIDEO_THUMB_RE.search(block)
        if tm:
            out["thumbnail"] = tm.group(1)
        dm = DURATION_RE.search(block)
        if dm:
            secs = duration_from(dm.group(1).strip())
            if secs is not None:
                out["duration_seconds"] = secs
        return out

    m = MEDIA_LINK_RE.search(block)
    if m:
        css, href = m.groups()
        out = {"file": href}
        media_type = MEDIA_TYPES.get(css)
        if media_type:
            out["media_type"] = media_type
        tm = TITLE_BOLD_RE.search(block)
        sm = STATUS_RE.search(block)
        if sm:
            status = plain_text(sm.group(1)).strip()
            secs = duration_from(status)
            if secs is not None:
                out["duration_seconds"] = secs
            else:
                out["status"] = status
        if media_type is None and tm:
            out["file_name"] = plain_text(tm.group(1)).strip()
        return out

    return {}


def extract_reactions(block: str):
    """Reactions span of one message -> official-style reactions list."""
    m = REACTIONS_OPEN_RE.search(block)
    if not m:
        return None
    reactions = []
    chunks = block[m.end():].split('<span class="reaction')[1:]
    for chunk in chunks:
        em = REACTION_EMOJI_RE.search(chunk)
        if not em:
            continue
        who = [htmllib.unescape(w) for w in REACTION_WHO_RE.findall(chunk)]
        cm = REACTION_COUNT_RE.search(chunk)
        reactions.append({
            "type": "emoji",
            "count": int(cm.group(1)) if cm else max(len(who), 1),
            "emoji": htmllib.unescape(em.group(1)),
            "recent": [{"from": w} for w in who],
        })
    return reactions or None


def message_to_dict(msg):
    """One fuser Message -> JSON-serializable dict."""
    # enhanced exports: normalize quotes / inline players back to the
    # original Telegram markup so a single set of patterns applies
    block = revert_media(revert_quotes(msg.html))

    entry = {"id": msg.msg_id,
             "type": msg.kind if msg.kind == "service" else "message"}
    date_iso, date_unix = parse_date(block)
    if date_iso:
        entry["date"] = date_iso
        if date_unix:
            entry["date_unixtime"] = date_unix
    sender = htmllib.unescape(msg.sender) if msg.sender else None

    if msg.kind == "service":
        if sender:
            entry["actor"] = sender
        bm = SERVICE_BODY_RE.search(block)
        entry["text"] = plain_text(bm.group(1)).strip() if bm else ""
        entry["text_entities"] = []
        return entry

    # calls appear as regular messages in the HTML export but are
    # service messages with action phone_call in Telegram's JSON
    if MEDIA_CALL_RE.search(block):
        entry["type"] = "service"
        if sender:
            entry["actor"] = sender
        entry["action"] = "phone_call"
        sm = STATUS_RE.search(block)
        status = plain_text(sm.group(1)).strip() if sm else ""
        secs = duration_from(status)
        if secs is not None:
            entry["duration_seconds"] = secs
            entry["discard_reason"] = "hangup"
        else:
            low = status.lower()
            for needle, reason in CALL_REASONS:
                if needle in low:
                    entry["discard_reason"] = reason
                    break
        if status:
            entry["status"] = status
        entry["text"] = ""
        entry["text_entities"] = []
        return entry

    if sender:
        entry["from"] = sender

    fm = FORWARDED_FROM_RE.search(block)
    if fm:
        entry["forwarded_from"] = htmllib.unescape(
            re.sub(r"\s+", " ", fm.group(1)).strip())

    rm = REPLY_TO_RE.search(block)
    if rm:
        entry["reply_to_message_id"] = int(rm.group(1))

    entry.update(extract_media(block))

    tm = TEXT_DIV_RE.search(block)
    entities = text_entities(tm.group(1)) if tm else []
    entry["text"] = entities_to_text(entities)
    entry["text_entities"] = entities

    reactions = extract_reactions(block)
    if reactions:
        entry["reactions"] = reactions
    return entry


def to_json(export_dir, out_file=None, indent=1, faithful=False):
    """HTML -> JSON. Parse export_dir and write the JSON file.

    faithful=True keeps ONLY the keys of Telegram's official JSON
    schema — a destructive conversion: the extra data preserved by the
    default enriched mode (call direction/status texts, file names,
    the generator mark) is dropped, AND the HTML-only pages and static
    assets (messages*.html, css/, js/, images/) are deleted so the
    folder ends up matching Telegram's own JSON export layout exactly.
    """
    d = Path(export_dir).resolve()
    report_stage("scan", name=d.name)
    messages, header_html, sender_headers = parse_export(d)

    # single-export "merge": sorts by id and dedups anchored service blocks
    merged = merge_messages([(messages, header_html, sender_headers)])

    report_stage("convert")
    entries = [message_to_dict(m) for m in merged]
    real = sum(1 for m in merged if m.msg_id > 0)

    if faithful:
        for e in entries:
            for k in ENRICHED_KEYS:
                e.pop(k, None)
        doc = {"name": chat_title(header_html) or "", "messages": entries}
    else:
        doc = {"name": chat_title(header_html) or "",
               "generated_by": GENERATOR,
               "messages": entries}

    out = Path(out_file).resolve() if out_file else d / "result.json"
    if out_file is None:
        _guard_overwrite(out, "generated_by")
    report_stage("write")
    out.parent.mkdir(parents=True, exist_ok=True)
    with out.open("w", encoding="utf-8") as f:
        json.dump(doc, f, ensure_ascii=False, indent=indent)
        f.write("\n")

    removed_assets = False
    if faithful and out_file is None:
        _remove_html_assets(d)
        removed_assets = True

    print(f"Converted {real} messages from {d}")
    print(f"Wrote {out} ({out.stat().st_size // 1024} KB)")
    if removed_assets:
        print("Removed the HTML pages and web assets "
              "(messages*.html, css/, js/, images/)")
    return {
        "messages": real,
        "out_file": str(out),
        "out_dir": str(out.parent),
        "removed_assets": removed_assets,
    }


# ===========================================================================
# JSON -> HTML
# ===========================================================================

HEADER_TEMPLATE = """<!DOCTYPE html>
<html>

 <head>

  <meta charset="utf-8"/>
<title>Exported Data</title>
  <meta content="width=device-width, initial-scale=1.0" name="viewport"/>

  <link href="css/style.css" rel="stylesheet"/>

  <script src="js/script.js" type="text/javascript">

  </script>

 </head>

 <body onload="CheckLocation();">

  <div class="page_wrap">

   <div class="page_header">

    <div class="content">

     <div class="text bold">
{title}
     </div>

    </div>

   </div>

   <div class="page_body chat_page">

    <div class="history">"""

# Telegram Desktop's peer color mapping: color = LOOKUP[peer_id % 7]
USERPIC_COLORS = [0, 7, 4, 1, 6, 3, 5]

# MessageEntity type -> HTML tag pair of the Telegram HTML export
ENTITY_TAGS = {"bold": ("<strong>", "</strong>"),
               "italic": ("<em>", "</em>"),
               "code": ("<code>", "</code>"),
               "pre": ("<pre>", "</pre>"),
               "underline": ("<u>", "</u>"),
               "strikethrough": ("<s>", "</s>"),
               "spoiler": ('<span class="spoiler">', "</span>")}


def esc(text: str) -> str:
    return htmllib.escape(str(text), quote=False)


def initials_of(name: str) -> str:
    words = [w for w in name.split() if w]
    return "".join(w[0] for w in words[:2]).upper() or "?"


def userpic_index(entry: dict) -> int:
    """Stable 1..8 color index: Telegram's own mapping when a numeric
    from_id/actor_id is available, a name hash otherwise."""
    peer = entry.get("from_id") or entry.get("actor_id") or ""
    digits = re.sub(r"\D", "", str(peer))
    if digits:
        key = int(digits)
    else:
        name = entry.get("from") or entry.get("actor") or "?"
        key = sum(name.encode("utf-8"))
    return USERPIC_COLORS[key % 7] + 1


def date_title(date: datetime, unixtime) -> str:
    """'24.01.2026 17:54:24 UTC+01:00' — the offset is derived from the
    unixtime, so it is the REAL offset of the message (DST included)."""
    base = date.strftime("%d.%m.%Y %H:%M:%S")
    if not unixtime:
        return base
    off = calendar.timegm(date.timetuple()) - int(unixtime)
    sign = "+" if off >= 0 else "-"
    off = abs(off)
    return f"{base} UTC{sign}{off // 3600:02d}:{off % 3600 // 60:02d}"


def fmt_duration(seconds) -> str:
    """21 -> '0:21', 3723 -> '1:02:03' (Telegram HTML style)."""
    s = int(seconds)
    if s >= 3600:
        return f"{s // 3600}:{s % 3600 // 60:02d}:{s % 60:02d}"
    return f"{s // 60}:{s % 60:02d}"


def human_size(n) -> str:
    n = float(n)
    for unit in ("B", "KB", "MB", "GB"):
        if n < 1024 or unit == "GB":
            return f"{n:.0f} B" if unit == "B" else f"{n:.1f} {unit}"
        n /= 1024
    return f"{n:.1f} GB"


def entities_html(entry: dict) -> str:
    """Official "text"/"text_entities" -> the inline HTML of a text div."""
    parts = entry.get("text_entities")
    if parts is None:
        text = entry.get("text", "")
        parts = [text] if isinstance(text, str) else text
    out = []
    for p in parts:
        if isinstance(p, str) or p.get("type") == "plain":
            text = p if isinstance(p, str) else p["text"]
            out.append(esc(text).replace("\n", "<br>"))
            continue
        kind, text = p.get("type"), esc(p.get("text", ""))
        if kind == "link":
            out.append(f'<a href="{p["text"]}">{text}</a>')
        elif kind == "text_link":
            out.append(f'<a href="{p.get("href", "")}">{text}</a>')
        elif kind == "custom_emoji":
            out.append(f'<a href="{p.get("document_id", "")}">{text}</a>')
        elif kind in ENTITY_TAGS:
            o, c = ENTITY_TAGS[kind]
            out.append(o + text.replace("\n", "<br>") + c)
        else:  # mention, hashtag, phone, email, ... -> plain text
            out.append(text.replace("\n", "<br>"))
    return "".join(out)


def media_html(entry: dict) -> str:
    """Media fields of a JSON message -> the media_wrap block, or ''."""
    photo = entry.get("photo")
    if photo:
        style = ""
        w, h = entry.get("width"), entry.get("height")
        if w and h:
            scale = min(260 / max(int(w), int(h)), 1)
            style = (f' style="width: {int(int(w) * scale)}px; '
                     f'height: {int(int(h) * scale)}px"')
        return (f'       <div class="media_wrap clearfix">\n'
                f'        <a class="photo_wrap clearfix pull_left" '
                f'href="{photo}">\n'
                f'         <img class="photo" src="{photo}"{style}/>\n'
                f'        </a>\n'
                f'       </div>\n')

    media_type = entry.get("media_type")
    file = entry.get("file")

    if media_type == "sticker" and file:
        thumb = entry.get("thumbnail") or file
        return (f'       <div class="media_wrap clearfix">\n'
                f'        <a class="sticker_wrap clearfix pull_left" '
                f'href="{file}">\n'
                f'         <img class="sticker" src="{thumb}"/>\n'
                f'        </a>\n'
                f'       </div>\n')

    if media_type in ("video_file", "video_message", "animation") and file:
        thumb = entry.get("thumbnail") or f"{file}_thumb.jpg"
        dur = entry.get("duration_seconds")
        dur_div = (f'         <div class="video_duration">\n'
                   f'{fmt_duration(dur)}\n'
                   f'         </div>\n' if dur is not None else "")
        return (f'       <div class="media_wrap clearfix">\n'
                f'        <a class="video_file_wrap clearfix pull_left" '
                f'href="{file}">\n'
                f'         <div class="video_play_bg">\n'
                f'          <div class="video_play">\n'
                f'          </div>\n'
                f'         </div>\n'
                f'{dur_div}'
                f'         <img class="video_file" src="{thumb}"/>\n'
                f'        </a>\n'
                f'       </div>\n')

    if file:
        if media_type == "voice_message":
            css, title = "media_voice_message", "Voice message"
        elif media_type == "audio_file":
            css = "media_audio_file"
            title = entry.get("title") or "Audio file"
        else:
            css = "media_file"
            title = (entry.get("file_name")
                     or file.rsplit("/", 1)[-1])
        dur = entry.get("duration_seconds")
        status = (entry.get("status")
                  or (fmt_duration(dur) if dur is not None else None)
                  or (human_size(entry["file_size"])
                      if entry.get("file_size") else None))
        status_div = (f'          <div class="status details">\n'
                      f'{esc(status)}\n'
                      f'          </div>\n' if status else "")
        return (f'       <div class="media_wrap clearfix">\n'
                f'        <a class="media clearfix pull_left block_link '
                f'{css}" href="{file}">\n'
                f'         <div class="fill pull_left">\n'
                f'         </div>\n'
                f'         <div class="body">\n'
                f'          <div class="title bold">\n'
                f'{esc(title)}\n'
                f'          </div>\n'
                f'{status_div}'
                f'         </div>\n'
                f'        </a>\n'
                f'       </div>\n')
    return ""


def call_html(entry: dict) -> str:
    """A phone_call service entry -> the media_call block the HTML
    export uses (calls are regular messages there)."""
    status = entry.get("status")  # enriched JSON keeps the exact text
    if not status:
        dur = entry.get("duration_seconds")
        reason = entry.get("discard_reason")
        if dur is not None:
            status = f"({int(dur)} seconds)"
        else:
            status = {"missed": "Missed", "busy": "Busy",
                      "disconnect": "Disconnected"}.get(reason, "Cancelled")
    ok = " success" if entry.get("duration_seconds") is not None else ""
    title = entry.get("actor") or "Call"
    return (f'       <div class="media_wrap clearfix">\n'
            f'        <div class="media clearfix pull_left media_call{ok}">\n'
            f'         <div class="fill pull_left">\n'
            f'         </div>\n'
            f'         <div class="body">\n'
            f'          <div class="title bold">\n'
            f'{esc(title)}\n'
            f'          </div>\n'
            f'          <div class="status details">\n'
            f'{esc(status)}\n'
            f'          </div>\n'
            f'         </div>\n'
            f'        </div>\n'
            f'       </div>\n')


def reactions_html(entry: dict) -> str:
    spans = []
    for r in entry.get("reactions") or []:
        pics = []
        for who in r.get("recent") or []:
            name = who.get("from") or "?"
            pics.append(
                f'          <div class="userpic userpic'
                f'{userpic_index(who)}" '
                f'style="width: 20px; height: 20px">\n'
                f'           <div class="initials" '
                f'style="line-height: 20px" title="{esc(name)}">\n'
                f'{initials_of(name)}\n'
                f'           </div>\n'
                f'          </div>\n')
        spans.append(
            f'        <span class="reaction">\n'
            f'         <span class="emoji">\n'
            f'{esc(r.get("emoji", ""))}\n'
            f'         </span>\n'
            f'         <span class="userpics">\n'
            f'{"".join(pics)}'
            f'         </span>\n'
            f'        </span>\n')
    if not spans:
        return ""
    return (f'       <span class="reactions">\n'
            f'{"".join(spans)}'
            f'       </span>\n')


def userpic_html(entry: dict, sender: str) -> str:
    return (f'      <div class="pull_left userpic_wrap">\n'
            f'       <div class="userpic userpic{userpic_index(entry)}" '
            f'style="width: 42px; height: 42px">\n'
            f'        <div class="initials" style="line-height: 42px">\n'
            f'{initials_of(sender)}\n'
            f'        </div>\n'
            f'       </div>\n'
            f'      </div>\n')


def from_name_html(sender: str) -> str:
    return (f'       <div class="from_name">\n'
            f'{esc(sender)}\n'
            f'       </div>\n')


def build_block(entry: dict, joined: bool):
    """One JSON message -> (html_block, kind, sender, date)."""
    mid = entry["id"]
    date = (datetime.fromisoformat(entry["date"])
            if entry.get("date") else None)
    is_call = entry.get("action") == "phone_call"

    if entry.get("type") == "service" and not is_call:
        text = entry.get("text")
        if isinstance(text, list):
            text = "".join(p if isinstance(p, str) else p.get("text", "")
                           for p in text)
        if not text:
            actor = entry.get("actor") or ""
            action = entry.get("action") or "service message"
            text = f"{actor} {action.replace('_', ' ')}".strip()
        block = (f'     <div class="message service" id="message{mid}">\n\n'
                 f'      <div class="body details">\n'
                 f'{esc(text)}\n'
                 f'      </div>\n\n'
                 f'     </div>')
        return block, "service", None, date

    sender = entry.get("from") or entry.get("actor") or "?"
    time_div = (f'       <div class="pull_right date details" '
                f'title="{date_title(date, entry.get("date_unixtime"))}">\n'
                f'{date.strftime("%H:%M")}\n'
                f'       </div>\n') if date else ""

    body = []
    reply = entry.get("reply_to_message_id")
    if reply:
        body.append(
            f'       <div class="reply_to details">\n'
            f'In reply to <a href="#go_to_message{reply}" '
            f'onclick="return GoToMessage({reply})">this message</a>\n'
            f'       </div>\n')

    if is_call:
        body.append(call_html(entry))
    else:
        media = media_html(entry)
        text_inner = entities_html(entry)
        text_div = (f'       <div class="text">\n'
                    f'{text_inner}\n'
                    f'       </div>\n') if text_inner else ""
        fwd = entry.get("forwarded_from")
        if fwd:
            inner = "".join(
                "  " + line if line else line
                for line in (media + text_div).splitlines(keepends=True))
            body.append(
                f'       <div class="forwarded body">\n'
                f'        <div class="from_name">\n'
                f'{esc(fwd)}\n'
                f'        </div>\n'
                f'{inner}'
                f'       </div>\n')
        else:
            body.append(media + text_div)
    body.append(reactions_html(entry))

    joined_cls = " joined" if joined else ""
    userpic = "" if joined else userpic_html(entry, sender)
    name_div = "" if joined else from_name_html(sender)
    block = (f'     <div class="message default clearfix{joined_cls}" '
             f'id="message{mid}">\n'
             f'{userpic}'
             f'      <div class="body">\n'
             f'{time_div}'
             f'{name_div}'
             f'{"".join(body)}'
             f'      </div>\n'
             f'     </div>')
    return block, "default", sender, date


def load_chat(json_file: Path) -> dict:
    doc = json.loads(json_file.read_text(encoding="utf-8"))
    if "chats" in doc:
        raise ValueError(
            "Este result.json es una exportación completa de la cuenta "
            "(contiene varios chats), no un chat individual. De momento "
            "solo se soportan exports de un chat concreto.")
    if "messages" not in doc:
        raise ValueError("El JSON no contiene la clave 'messages' — no "
                         "parece un export de chat de Telegram.")
    return doc


def write_assets(out_dir: Path):
    for rel, b64 in ASSETS.items():
        dest = out_dir / rel
        dest.parent.mkdir(parents=True, exist_ok=True)
        dest.write_bytes(base64.b64decode(b64))


def from_json(export_dir, page_size=None, force=False):
    """JSON -> HTML. result.json (or, if absent, result_enriched.json)
    in export_dir -> messages*.html + web assets, in place (the media
    folders already live there)."""
    d = Path(export_dir).resolve()
    json_file = d / "result.json"
    if not json_file.is_file():
        json_file = d / "result_enriched.json"
    if not json_file.is_file():
        raise ValueError(
            f"No se encontró result.json ni result_enriched.json en {d}")
    if not force and list(d.glob("messages*.html")):
        raise ValueError(
            "La carpeta ya contiene messages*.html — se sobrescribirían. "
            "Usa --force (o confirma en la interfaz) para regenerarlos.")

    report_stage("scan", name=d.name)
    doc = load_chat(json_file)
    entries = [e for e in doc["messages"] if isinstance(e.get("id"), int)]

    report_stage("convert")
    messages = []
    sender_headers = {}
    prev_sender, prev_day = None, None
    for i, e in enumerate(entries):
        if i % 100 == 0:
            report_stage("convert", frac=i / max(len(entries), 1))
        date = (datetime.fromisoformat(e["date"]) if e.get("date") else None)
        day = date.date() if date else None
        joined = (e.get("type") != "service"
                  and e.get("action") != "phone_call"
                  and e.get("from") is not None
                  and e.get("from") == prev_sender
                  and day is not None and day == prev_day)
        block, kind, sender, date = build_block(e, joined)
        if kind == "default":
            prev_sender, prev_day = sender, day
            if sender and sender not in sender_headers:
                sender_headers[sender] = (userpic_html(e, sender),
                                          from_name_html(sender).strip())
        else:
            prev_sender = None
        messages.append(Message(
            msg_id=e["id"], kind=kind, joined=joined, date=date,
            sender=sender, html=block, source=d))

    title = doc.get("name") or "Exported Data"
    header_html = HEADER_TEMPLATE.format(title=esc(title))
    write_assets(d)
    page_bytes = parse_size(page_size or DEFAULT_PAGE_SIZE)
    written = write_pages(messages, header_html, d, page_bytes,
                          sender_headers)
    print(f"Rebuilt {len(written)} page(s) from {json_file.name} "
          f"({len(messages)} messages) in {d}")
    return {
        "messages": len(messages),
        "pages": written,
        "out_dir": str(d),
    }


# ===========================================================================
# Both formats present: enrich the official JSON with the HTML's extras
# ===========================================================================

def enrich_json(export_dir, out_file=None):
    """Folder with BOTH exports: merge the extra fields recoverable from
    the HTML into the official result.json -> result_enriched.json.
    Neither original file is touched; official values always win."""
    d = Path(export_dir).resolve()
    json_file = d / "result.json"
    if not json_file.is_file():
        raise ValueError(f"No se encontró result.json en {d}")
    if not list(d.glob("messages*.html")):
        raise ValueError(f"No se encontró messages.html en {d}")

    report_stage("scan", name=d.name)
    doc = load_chat(json_file)
    parsed = parse_export(d)
    merged = merge_messages([parsed])

    report_stage("convert")
    html_entries = {}
    for m in merged:
        e = message_to_dict(m)
        html_entries[e["id"]] = e

    added_fields = 0
    added_msgs = 0
    by_id = {}
    for m in doc["messages"]:
        if isinstance(m.get("id"), int):
            by_id[m["id"]] = m
    for mid, e in html_entries.items():
        m = by_id.get(mid)
        if m is None:
            if mid > 0:  # message present in the HTML but not in the JSON
                doc["messages"].append(e)
                added_msgs += 1
            continue
        for k, v in e.items():
            if k not in m:
                m[k] = v
                added_fields += 1
    if added_msgs:
        doc["messages"].sort(
            key=lambda m: m.get("id") if isinstance(m.get("id"), int) else 0)
    doc["enriched_by"] = GENERATOR

    out = Path(out_file).resolve() if out_file else d / "result_enriched.json"
    if out_file is None:
        _guard_overwrite(out, "enriched_by")
    report_stage("write")
    with out.open("w", encoding="utf-8") as f:
        json.dump(doc, f, ensure_ascii=False, indent=1)
        f.write("\n")
    print(f"Enriched {len(doc['messages'])} messages "
          f"(+{added_fields} fields, +{added_msgs} messages from HTML)")
    print(f"Wrote {out} ({out.stat().st_size // 1024} KB)")
    return {
        "messages": len(doc["messages"]),
        "added_fields": added_fields,
        "added_msgs": added_msgs,
        "out_file": str(out),
        "out_dir": str(d),
    }


def downgrade_json(export_dir, out_file=None):
    """Folder with ONLY a result_enriched.json (no HTML, no official
    result.json): strip this tool's extras (ENRICHED_KEYS, the
    enriched_by/generated_by marks) back to a plain, official-schema
    result.json. DESTRUCTIVE: the recovered call status texts, file
    names etc. are dropped, same as the faithful HTML -> JSON mode."""
    d = Path(export_dir).resolve()
    src = d / "result_enriched.json"
    if not src.is_file():
        raise ValueError(f"No se encontró result_enriched.json en {d}")

    report_stage("scan", name=d.name)
    doc = json.loads(src.read_text(encoding="utf-8"))
    doc.pop("enriched_by", None)
    doc.pop("generated_by", None)
    report_stage("convert")
    for e in doc.get("messages", []):
        for k in ENRICHED_KEYS:
            e.pop(k, None)

    out = Path(out_file).resolve() if out_file else d / "result.json"
    if out_file is None:
        _guard_overwrite(out, "generated_by")
    report_stage("write")
    with out.open("w", encoding="utf-8") as f:
        json.dump(doc, f, ensure_ascii=False, indent=1)
        f.write("\n")

    count = len(doc.get("messages", []))
    print(f"Downgraded {count} messages to the official format")
    print(f"Wrote {out} ({out.stat().st_size // 1024} KB)")
    return {
        "messages": count,
        "out_file": str(out),
        "out_dir": str(d),
    }


# ===========================================================================
# Detection & CLI
# ===========================================================================

def detect_formats(export_dir) -> dict:
    """What does the folder contain? ->
    {"html": bool, "json": bool, "enriched": bool}."""
    d = Path(export_dir)
    return {"html": bool(list(d.glob("messages*.html"))),
            "json": (d / "result.json").is_file(),
            "enriched": (d / "result_enriched.json").is_file()}


def main():
    ap = argparse.ArgumentParser(
        description="Convert a Telegram chat export between HTML and JSON "
                    "(both directions, auto-detected), or enrich the "
                    "official JSON with the extra data of the HTML export. "
                    "Media files are never copied.")
    ap.add_argument("export", help="export folder (HTML, JSON or both)")
    mode = ap.add_mutually_exclusive_group()
    mode.add_argument("--to-json", action="store_true",
                      help="force HTML -> JSON")
    mode.add_argument("--to-html", action="store_true",
                      help="force JSON -> HTML")
    mode.add_argument("--enrich", action="store_true",
                      help="the folder holds BOTH exports: merge the "
                           "HTML's extra data into the official JSON "
                           "(-> result_enriched.json)")
    mode.add_argument("--downgrade", action="store_true",
                      help="the folder holds ONLY a result_enriched.json: "
                           "strip this tool's extra data back to the "
                           "official result.json. DESTRUCTIVE.")
    ap.add_argument("-o", "--output", default=None,
                    help="output JSON file for --to-json / --enrich / "
                         "--downgrade (default: result.json / "
                         "result_enriched.json inside the export folder)")
    ap.add_argument("--faithful", action="store_true",
                    help="HTML -> JSON only. DESTRUCTIVE: keep only the "
                         "keys of Telegram's official JSON schema, "
                         "dropping the extra data preserved by the "
                         "default enriched mode (call status texts, "
                         "file names, generator mark)")
    group = ap.add_mutually_exclusive_group()
    group.add_argument("--indent", type=int, default=1,
                       help="HTML -> JSON: indentation level (default: 1)")
    group.add_argument("--compact", action="store_true",
                       help="HTML -> JSON: single-line JSON")
    ap.add_argument("-s", "--page-size", default=DEFAULT_PAGE_SIZE,
                    help="JSON -> HTML: approximate size of each "
                         "messagesN.html page, e.g. 500KB, 2MB; 0 = "
                         f"single file (default: {DEFAULT_PAGE_SIZE})")
    ap.add_argument("-f", "--force", action="store_true",
                    help="JSON -> HTML: overwrite existing messages*.html")
    args = ap.parse_args()

    export_dir = Path(args.export).resolve()
    if not export_dir.is_dir():
        sys.exit(f"error: {export_dir} is not a directory")

    found = detect_formats(export_dir)
    if not (args.to_json or args.to_html or args.enrich or args.downgrade):
        if found["html"] and found["json"]:
            sys.exit(
                "error: la carpeta contiene A LA VEZ el export HTML y el "
                "JSON. Convertir de nuevo no aporta nada; lo útil es "
                "enriquecer el JSON oficial con los datos extra del HTML: "
                "vuelve a ejecutar con --enrich (o elige la dirección con "
                "--to-json / --to-html --force).")
        if found["html"]:
            args.to_json = True
        elif found["json"] or found["enriched"]:
            args.to_html = True
        else:
            sys.exit(f"error: {export_dir} no contiene messages.html, "
                     "result.json ni result_enriched.json")

    try:
        if args.downgrade:
            if not found["enriched"]:
                sys.exit(f"error: no hay result_enriched.json en "
                         f"{export_dir}")
            downgrade_json(export_dir, args.output)
        elif args.enrich:
            enrich_json(export_dir, args.output)
        elif args.to_json:
            if not found["html"]:
                sys.exit(f"error: no hay messages*.html en {export_dir}")
            to_json(export_dir, args.output,
                    indent=None if args.compact else args.indent,
                    faithful=args.faithful)
        else:
            if not (found["json"] or found["enriched"]):
                sys.exit(f"error: no hay result.json ni "
                         f"result_enriched.json en {export_dir}")
            from_json(export_dir, args.page_size, force=args.force)
    except ValueError as e:
        sys.exit(f"error: {e}")


# ---------------------------------------------------------------------------
# Embedded web assets of a Telegram HTML export (css/, js/, images/),
# zlib-compressed JSON {relative_path: base64_content}. Regenerable from
# any Telegram HTML export with tools/pack_assets.py.
# ---------------------------------------------------------------------------

ASSETS_BLOB = ""

ASSETS = json.loads(zlib.decompress(base64.b64decode(ASSETS_BLOB)))


if __name__ == "__main__":
    main()
